    /** Visitor handles custom elements with nested content */
    public function test_visitor_custom_element_with_nesting(): void
    {
        $visitor = new class {
            public function visit_custom_element($ctx, $tagName, $html) {
                return ['custom' => "[CUSTOM WIDGET]"];
            }
        };
        $options = \HtmlToMarkdown\ConversionOptions::default();
        $options->setVisitor($visitor);
        $result = HtmlToMarkdown::convert("<div><custom-widget data-value=\"123\"><p>Widget content here</p><span>With nested elements</span></custom-widget></div>", $options);
        $this->assertStringContainsString("[CUSTOM WIDGET]", $result);
        $this->assertStringNotContainsString("Widget content here", $result);
    }

    /** Visitor skips deeply nested elements */
    public function test_visitor_deeply_nested_skip(): void
    {
        $visitor = new class {
            public function visit_mark($ctx, $text) {
                return 'skip';
            }
        };
        $options = \HtmlToMarkdown\ConversionOptions::default();
        $options->setVisitor($visitor);
        $result = HtmlToMarkdown::convert("<div><p>Outer <em>emphasis <strong>with bold <mark>and highlight</mark></strong></em> text</p></div>", $options);
        $this->assertStringContainsString("Outer", $result);
        $this->assertStringContainsString("text", $result);
        $this->assertStringNotContainsString("highlight", $result);
    }

    /** Visitor modifies element at end after children processed */
    public function test_visitor_element_end_modification(): void
    {
        $visitor = new class {
            public function visit_element_end($ctx, $output) {
                return ['custom' => "MODIFIED OUTPUT"];
            }
        };
        $options = \HtmlToMarkdown\ConversionOptions::default();
        $options->setVisitor($visitor);
        $result = HtmlToMarkdown::convert("<blockquote><p>Original quote</p></blockquote>", $options);
        $this->assertNotEmpty($result);
    }

    /** Visitor skips at element_start level removes entire subtree */
    public function test_visitor_element_start_skip_entire_subtree(): void
