        $this->assertNotEmpty($result);
    }

    /** Visitor preserves unknown HTML tags as raw HTML */
    public function test_visitor_unknown_tag_preservation(): void
    {
        $visitor = new class {
            public function visit_custom_element($ctx, $tagName, $html) {
                return 'preserve_html';
            }
        };
        $options = \HtmlToMarkdown\ConversionOptions::default();
        $options->setVisitor($visitor);
        $result = HtmlToMarkdown::convert("<article><p>Article text</p><x-custom>Custom element with content</x-custom><p>More article text</p></article>", $options);
